export default function About() {
  return (
    <div className="p-6 max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold"></h1>
      <p className="mt-4 text-gray-600">Our mission is to connect people with great local food while supporting neighborhood kitchens. We deliver fresh, affordable meals quickly and sustainably. Our vision is to become the most trusted food delivery service, prioritizing quality, community, and convenience for every customer.</p>

      <section className="mt-6 bg-white p-4 rounded shadow">
        <h2 className="font-semibold">Our Values</h2>
        <ul className="mt-3 list-disc list-inside text-gray-600">
          <li>Quality ingredients</li>
          <li>Fast delivery</li>
          <li>Friendly customer service</li>
        </ul>
      </section>
    </div>
  );
}
